import React from "react";
import "./Home.css";
import Grid from "@material-ui/core/Grid";
import Switch from "@material-ui/core/Switch";
import Slider from "@material-ui/core/Slider";
import Container from "@material-ui/core/Container";

class Home extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      state_status: true,
      brightness_status: true,
      brightness_value: 0,
      red_rgb: 0,
      green_rgb: 0,
      blue_rgb: 0,
      data: this.props.data,
    };
  }

  componentDidMount() {
    this.setState({
      state_status: !!parseInt(this.state.data["STATE_STATUS"]) ? true : false,
      brightness_status: !!parseInt(this.state.data["BRIGHTNESS_STATUS"])
        ? false
        : true,
      brightness_value: this.state.data["BRIGHTNESS_VALUE"],
      red_rgb: this.state.data["RED_RGB"],
      green_rgb: this.state.data["GREEN_RGB"],
      blue_rgb: this.state.data["BLUE_RGB"],
    });
  }

  handleChange = (event, value) => {
    this.setState({ [event.target.id]: value });
  };

  endSlider = (e) => {
    console.log("end");
  };
  render() {
    const const_brightness_value = this.state.brightness_value;
    const const_red_rgb = this.state.red_rgb;
    const const_green_rgb = this.state.green_rgb;
    const const_blue_rgb = this.state.blue_rgb;

    return (
      <div className="Home">
        <Container maxWidth="xs">
          <Grid container spacing={2}>
            <Grid item xs={6}>
              Status
            </Grid>
            <p>
              The switch is{" "}
              <span>{this.state.state_status ? "on" : "off"}</span>.
            </p>
            <Grid item xs={6}>
              <Switch
                id="state_status"
                color="primary"
                checked={this.state.state_status}
                onChange={this.handleChange}
              />
            </Grid>
            <Grid item xs={12}>
              <hr></hr>
            </Grid>
            <Grid item xs={6}>
              Light Sensor
            </Grid>
            <p>
              The switch is{" "}
              <span>{this.state.brightness_status ? "on" : "off"}</span>.
            </p>
            <Grid item xs={6}>
              <Switch
                id="brightness_status"
                color="primary"
                checked={this.state.brightness_status}
                onChange={this.handleChange}
              />
            </Grid>
            <Grid item xs={12}>
              Brightness
            </Grid>
            <p>
              The value is <span>{this.state.brightness_value}</span>.
            </p>
            <Grid item xs={12}>
              <Slider
                value={const_brightness_value}
                aria-labelledby="continuous-slider"
                min={0}
                max={255}
                onChangeCommitted={(event, value) => {
                  this.setState({ brightness_value: value });
                }}
                onChange={(event, value) => {
                  this.setState({ brightness_value: value });
                }}
              />
            </Grid>
            <Grid item xs={12}>
              <hr></hr>
            </Grid>
            <Grid item xs={12}>
              Red
            </Grid>
            <Grid item xs={12}>
              {this.state.red_rgb}
              <Slider
              value = {this.state.red_rgb}
                aria-labelledby="continuous-slider"
                min={0}
                max={255}
                onChange={(event, value) => {
                  this.setState({ red_rgb: value });
                }}
                onChangeCommitted={(event, value) => {
                  this.setState({ red_rgb: value });
                }}
              />
            </Grid>
            <Grid item xs={12}>
              Green
            </Grid>
            <Grid item xs={12}>
              <Slider
                value={this.state.green_rgb}
                id="green_rgb"
                aria-labelledby="continuous-slider"
                min={0}
                max={255}
                onDragEnd={this.handleChange}
              />
            </Grid>
            <Grid item xs={12}>
              Blue
            </Grid>
            <Grid item xs={12}>
              <Slider
                value={this.state.blue_rgb}
                id="blue_rgb"
                aria-labelledby="continuous-slider"
                min={0}
                max={255}
                onDragEnd={this.handleChange}
              />
            </Grid>
          </Grid>
        </Container>
      </div>
    );
  }
}

export default Home;
